# ── STEP 3: BUSINESS LOGIC (NO AI) ──────────────────────────────────────────
# Rules engine: compliance checks, missing data detection, upsell triggers.
# Zero AI cost — pure Python.

import re

job  = _input.first().json
ai   = job.get('ai', {})

issues   = []  # dicts: type / message / severity
warnings = []  # plain strings
upsells  = []  # plain strings

# ── COMPLIANCE CHECKS ────────────────────────────────────────────────────────

# 1. Customer email required for delivery (column: Customer email)
email = job.get('customer_email', '')
if not email or '@' not in email:
    issues.append({
        'type': 'MISSING_EMAIL',
        'message': 'Customer email is missing — report cannot be delivered',
        'severity': 'CRITICAL'
    })

# 2. Service address must be present
if not job.get('service_address', '').strip():
    issues.append({
        'type': 'MISSING_ADDRESS',
        'message': 'Service address not recorded',
        'severity': 'WARNING'
    })

# 3. Technician notes minimum length (column: Notes)
notes = job.get('technician_notes', '')
if len(notes.strip()) < 20:
    issues.append({
        'type': 'INSUFFICIENT_NOTES',
        'message': 'Technician notes are too brief (under 20 characters)',
        'severity': 'WARNING'
    })

# 4. Assigned technician must be set
if not job.get('assigned_technician', '').strip() or job.get('assigned_technician') == 'Unknown':
    issues.append({
        'type': 'NO_TECHNICIAN',
        'message': 'No technician assigned to this job',
        'severity': 'WARNING'
    })

# 5. Duration sanity check (only if both timestamps present)
duration = job.get('duration_mins')
if duration is not None:
    if duration < 5:
        warnings.append('Job duration under 5 minutes — possible timestamp error')
    elif duration > 480:
        warnings.append('Job duration over 8 hours — please verify timestamps')

# 6. High-priority jobs should have no unreviewed urgent flags
if job.get('priority') == 'High' and not ai.get('urgent_flags'):
    warnings.append('High-priority job — verify all safety checks were completed')

# 7. Urgent flags raised by AI
for flag in ai.get('urgent_flags', []):
    if 'manual review' not in flag.lower():
        issues.append({
            'type': 'URGENT_AI_FLAG',
            'message': f'Urgent item flagged: {flag}',
            'severity': 'URGENT'
        })

# 8. Follow-up marked required but no reason given
if ai.get('follow_up_required') and not ai.get('follow_up_reason'):
    warnings.append('Follow-up is required but no reason was documented')

# ── UPSELL TRIGGERS ───────────────────────────────────────────────────────────
# Scan description + cleaned notes + issues
search_text = ' '.join([
    job.get('description', ''),
    ai.get('cleaned_notes', ''),
    ' '.join(ai.get('issues_found', []))
]).lower()

upsell_rules = [
    (r'old|aged|worn|deteriorat|corrode|rust',
     'Unit showing age — consider a preventive maintenance package'),
    (r'filter|dirty|clogged|blocked',
     'Filter replacement or cleaning service recommended'),
    (r'leak|drip|moisture|water damage',
     'Plumbing inspection recommended following reported leak'),
    (r'noise|rattle|vibrat|bang',
     'Vibration dampening or mechanical inspection recommended'),
    (r'hvac|air.?con|cooling|heating|refriger',
     'Annual HVAC service contract available — priority scheduling included'),
]

for pattern, suggestion in upsell_rules:
    if re.search(pattern, search_text):
        upsells.append(suggestion)

if duration and duration > 180:
    upsells.append('Extended job — consider a service contract for priority response times')

# ── GATE DECISION ─────────────────────────────────────────────────────────────
has_critical    = any(i['severity'] == 'CRITICAL' for i in issues)
can_send_report = not has_critical

return [{
    'json': {
        **job,
        'compliance': {
            'issues':          issues,
            'warnings':        warnings,
            'upsells':         upsells,
            'has_critical':    has_critical,
            'can_send_report': can_send_report
        }
    }
}]

# ── STEP 4: PREMIUM AI — Claude Sonnet ───────────────────────────────────────
# Runs ONLY when the compliance gate clears.
# Generates customer-friendly narrative + internal technical report.
#
# Passes real column values into the prompt:
#   job_title, job_number, priority, customer_name, service_address,
#   assigned_technician, scheduled_date, description, job_updates

import json
import urllib.request

job  = _input.first().json
ai   = job.get('ai', {})
comp = job.get('compliance', {})

system_prompt = """You are a professional field service report writer for a trades and maintenance company.
Generate two outputs from the structured technician data provided.
Respond ONLY with valid JSON — no markdown fences, no explanation.

Output schema:
{
  "customer_summary": {
    "headline": "One sentence summarising the visit outcome",
    "what_we_did": "2-3 paragraph customer-friendly explanation — no jargon",
    "what_we_found": "Plain-English description of findings",
    "recommendations": ["1-3 actionable recommendations for the customer"],
    "next_steps": "What happens next"
  },
  "internal_report": {
    "technical_summary": "Detailed technical narrative for internal records",
    "root_cause_analysis": "What caused the issue, or N/A",
    "compliance_notes": "Any compliance or safety observations",
    "billing_notes": "Notes relevant to invoicing"
  }
}"""

duration = job.get('duration_mins')
if duration:
    h, m = divmod(duration, 60)
    dur_str = f"{h}h {m}m" if h else f"{m}m"
else:
    dur_str = 'Not recorded'

updates_str = '\n'.join(f'  - {u}' for u in job.get('job_updates', [])) or '  None recorded'

user_prompt = f"""JOB TITLE: {job.get('job_title', 'General Service')}
JOB NUMBER: {job.get('job_number', 'N/A')}
PRIORITY: {job.get('priority', 'Normal')}
CUSTOMER: {job.get('customer_name', 'Unknown')}
SERVICE ADDRESS: {job.get('service_address', 'Not recorded')}
TECHNICIAN: {job.get('assigned_technician', 'Unknown')}
SCHEDULED DATE: {job.get('scheduled_date', 'Not recorded')}
DURATION: {dur_str}

CUSTOMER-REPORTED ISSUE:
{job.get('description', 'Not provided')}

CLEANED TECHNICIAN NOTES:
{ai.get('cleaned_notes', 'None')}

JOB UPDATES COMPLETED:
{updates_str}

ISSUES FOUND: {'; '.join(ai.get('issues_found', [])) or 'None reported'}
WORK PERFORMED: {'; '.join(ai.get('work_performed', [])) or 'General service'}
PARTS REPLACED: {', '.join(ai.get('parts_replaced', [])) or 'None'}
FOLLOW-UP REQUIRED: {'Yes — ' + (ai.get('follow_up_reason') or 'unspecified') if ai.get('follow_up_required') else 'No'}
URGENT FLAGS: {'; '.join(ai.get('urgent_flags', [])) or 'None'}
UPSELL OPPORTUNITIES: {'; '.join(comp.get('upsells', [])) or 'None'}
"""

payload = json.dumps({
    'model': 'claude-sonnet-4-20250514',
    'max_tokens': 1200,
    'system': system_prompt,
    'messages': [{'role': 'user', 'content': user_prompt}]
}).encode('utf-8')

req = urllib.request.Request(
    'https://api.anthropic.com/v1/messages',
    data=payload,
    headers={
        'x-api-key': _env.get('ANTHROPIC_API_KEY', ''),
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
    },
    method='POST'
)

try:
    with urllib.request.urlopen(req) as resp:
        response_data = json.loads(resp.read().decode('utf-8'))
    report_content = json.loads(response_data['content'][0]['text'].strip())
except Exception:
    # Fallback — populate from structured AI data so the PDF can still render
    report_content = {
        'customer_summary': {
            'headline':        f"Service completed for {job.get('customer_name', 'your property')}",
            'what_we_did':     ai.get('cleaned_notes', 'Service was completed as requested.'),
            'what_we_found':   ', '.join(ai.get('issues_found', [])) or 'No major issues found.',
            'recommendations': comp.get('upsells', []),
            'next_steps':      ai.get('follow_up_reason') if ai.get('follow_up_required') else 'No follow-up required.'
        },
        'internal_report': {
            'technical_summary':   ai.get('cleaned_notes', 'See technician notes.'),
            'root_cause_analysis': 'N/A',
            'compliance_notes':    '; '.join(comp.get('warnings', [])) or 'None',
            'billing_notes':       f"Duration: {dur_str}. Parts: {', '.join(ai.get('parts_replaced', [])) or 'none'}."
        }
    }

return [{'json': {**job, 'report_content': report_content}}]
